import statistics
from collections import deque
from datetime import date, timedelta
from typing import Optional

class TokenUsageForecaster:
    """
    Weighted moving average forecaster for daily LLM token consumption.
    Applies a simple weekly seasonality multiplier derived from historical data.
    """

    def __init__(self, window: int = 7, seasonality_weeks: int = 4):
        self.window = window
        self.seasonality_weeks = seasonality_weeks
        self.history: list[tuple[date, int]] = []

    def record(self, day: date, tokens: int) -> None:
        """Append an observed token count for a given calendar day."""
        self.history.append((day, tokens))

    def _weekday_multipliers(self) -> dict[int, float]:
        by_dow: dict[int, list[int]] = {i: [] for i in range(7)}
        for day, tokens in self.history:
            by_dow[day.weekday()].append(tokens)
        overall_mean = statistics.mean(v for vals in by_dow.values() for v in vals)
        return {
            dow: (statistics.mean(vals) / overall_mean if vals else 1.0)
            for dow, vals in by_dow.items()
        }

    def _moving_average(self) -> float:
        if not self.history:
            raise ValueError("No history recorded")
        window_tokens = [t for _, t in self.history[-self.window:]]
        weights = range(1, len(window_tokens) + 1)
        weighted_sum = sum(w * v for w, v in zip(weights, window_tokens))
        return weighted_sum / sum(weights)

    def forecast(self, horizon_days: int = 30) -> list[dict]:
        """Return daily token forecasts for the next horizon_days."""
        base = self._moving_average()
        multipliers = self._weekday_multipliers()
        last_day = self.history[-1][0] if self.history else date.today()
        results = []
        for offset in range(1, horizon_days + 1):
            target = last_day + timedelta(days=offset)
            m = multipliers.get(target.weekday(), 1.0)
            predicted = int(base * m)
            results.append({"date": str(target), "predicted_tokens": predicted})
        return results

    def quota_recommendation(
        self,
        horizon_days: int = 30,
        safety_factor: float = 1.25,
    ) -> dict:
        """Total token budget recommendation with a safety margin."""
        daily = self.forecast(horizon_days)
        total = sum(d["predicted_tokens"] for d in daily)
        peak = max(d["predicted_tokens"] for d in daily)
        return {
            "horizon_days": horizon_days,
            "predicted_total": total,
            "peak_day_tokens": peak,
            "recommended_quota": int(total * safety_factor),
            "recommended_daily_limit": int(peak * safety_factor),
        }


if __name__ == "__main__":
    forecaster = TokenUsageForecaster(window=7, seasonality_weeks=4)
    today = date(2025, 6, 30)
    seed_data = [
        120_000, 135_000, 148_000, 90_000, 85_000, 200_000, 210_000,
        130_000, 145_000, 158_000, 95_000, 92_000, 215_000, 225_000,
        140_000, 150_000, 165_000, 100_000, 98_000, 230_000, 240_000,
    ]
    for i, tokens in enumerate(seed_data):
        forecaster.record(today - timedelta(days=len(seed_data) - i - 1), tokens)

    recs = forecaster.quota_recommendation(horizon_days=30, safety_factor=1.25)
    for k, v in recs.items():
        print(f"  {k}: {v:,}" if isinstance(v, int) else f"  {k}: {v}")
